SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>400000000.0) AND (t.Risk_Rating <= 6) AND (((t.CF_OA_5Y + t.CF_Invest_5Y )/5)/(t.OShares*t.Price + t.LtDebt_P0) > 0.03) AND ((t.CF_OA_P0+t.CF_OA_P1+t.CF_OA_P2+t.CF_OA_P3 + t.CF_Invest_P0 + t.CF_Invest_P1+ t.CF_Invest_P2+t.CF_Invest_P3)/(t.OShares*t.Price + t.LtDebt_P0)>0.24) AND ((t.Cash_P0/ (t.LtDebt_P0+1) > 0.098) OR (ABS(t.IntCov_P0) > 8.4)) AND (t.NP_P0 / NULLIF(t.NP_P1, 0)> 1.12) AND (t.NP_P1>0) AND (t.PE >3.4) AND (t.PE < 33.0) AND (t.ROE_Min3Y > 0.015) AND (t.NP_P0/ NULLIF(t.NP_P4, 0) > 1.05) ORDER BY t.ticker, t.time